create extension if not exists "pgcrypto";

-- ─── Enums ────────────────────────────────────────────────────────────────────

create type workspace_role as enum ('admin', 'contributor');
create type cluster_status as enum ('watching', 'investigating', 'in_roadmap', 'wont_solve');
create type signal_source as enum ('user_interview', 'sales_call', 'support_ticket', 'nps', 'slack', 'other');
create type business_impact as enum ('low', 'medium', 'high');

-- ─── Tables ───────────────────────────────────────────────────────────────────

create table workspaces (
  id          uuid primary key default gen_random_uuid(),
  name        text not null,
  slug        text not null unique,
  created_at  timestamptz not null default now()
);

create table workspace_members (
  id            uuid primary key default gen_random_uuid(),
  workspace_id  uuid not null references workspaces(id) on delete cascade,
  user_id       uuid not null references auth.users(id) on delete cascade,
  role          workspace_role not null default 'contributor',
  created_at    timestamptz not null default now(),
  unique(workspace_id, user_id)
);

create table problem_clusters (
  id            uuid primary key default gen_random_uuid(),
  workspace_id  uuid not null references workspaces(id) on delete cascade,
  name          text not null,
  description   text not null,
  status        cluster_status not null default 'watching',
  created_by    uuid not null references auth.users(id),
  created_at    timestamptz not null default now(),
  archived_at   timestamptz
);

create table open_questions (
  id          uuid primary key default gen_random_uuid(),
  cluster_id  uuid not null references problem_clusters(id) on delete cascade,
  question    text not null,
  created_by  uuid not null references auth.users(id),
  created_at  timestamptz not null default now()
);

create table signals (
  id                  uuid primary key default gen_random_uuid(),
  workspace_id        uuid not null references workspaces(id) on delete cascade,
  cluster_id          uuid references problem_clusters(id) on delete set null,
  problem_statement   text not null,
  verbatim_quote      text,
  source              signal_source not null,
  segments            text[] not null default '{}',
  business_impact     business_impact not null,
  signal_date         date not null default current_date,
  logged_by           uuid not null references auth.users(id),
  created_at          timestamptz not null default now()
);

create table share_links (
  id            uuid primary key default gen_random_uuid(),
  cluster_id    uuid not null references problem_clusters(id) on delete cascade,
  workspace_id  uuid not null references workspaces(id) on delete cascade,
  token         text not null unique default encode(gen_random_bytes(24), 'base64url'),
  created_by    uuid not null references auth.users(id),
  created_at    timestamptz not null default now(),
  revoked_at    timestamptz
);

create table invites (
  id            uuid primary key default gen_random_uuid(),
  workspace_id  uuid not null references workspaces(id) on delete cascade,
  email         text not null,
  role          workspace_role not null default 'contributor',
  token         text not null unique default encode(gen_random_bytes(24), 'base64url'),
  invited_by    uuid not null references auth.users(id),
  created_at    timestamptz not null default now(),
  accepted_at   timestamptz,
  revoked_at    timestamptz
);

-- ─── Indexes ──────────────────────────────────────────────────────────────────

create index on workspace_members (user_id);
create index on problem_clusters (workspace_id);
create index on signals (workspace_id);
create index on signals (cluster_id);
create index on signals (signal_date desc);
create index on share_links (token);
create index on invites (token);

-- ─── Row Level Security ───────────────────────────────────────────────────────

alter table workspaces         enable row level security;
alter table workspace_members  enable row level security;
alter table problem_clusters   enable row level security;
alter table open_questions     enable row level security;
alter table signals            enable row level security;
alter table share_links        enable row level security;
alter table invites            enable row level security;

-- Helper: is the current user a member of a given workspace?
create or replace function is_workspace_member(wid uuid)
returns boolean language sql security definer as $$
  select exists (
    select 1 from workspace_members
    where workspace_id = wid and user_id = auth.uid()
  );
$$;

-- Helper: is the current user an admin of a given workspace?
create or replace function is_workspace_admin(wid uuid)
returns boolean language sql security definer as $$
  select exists (
    select 1 from workspace_members
    where workspace_id = wid and user_id = auth.uid() and role = 'admin'
  );
$$;

-- ─── Workspace creation function ─────────────────────────────────────────────
-- Handles workspace + admin member insert atomically, bypassing RLS bootstrap problem

create or replace function create_workspace(
  workspace_name text,
  workspace_slug text
)
returns uuid
language plpgsql
security definer
as $$
declare
  new_workspace_id uuid;
begin
  insert into workspaces (name, slug)
  values (workspace_name, workspace_slug)
  returning id into new_workspace_id;

  insert into workspace_members (workspace_id, user_id, role)
  values (new_workspace_id, auth.uid(), 'admin');

  return new_workspace_id;
end;
$$;

-- ─── RLS Policies ─────────────────────────────────────────────────────────────

-- workspaces
create policy "authenticated users can create workspaces"
  on workspaces for insert
  to authenticated
  with check (true);

create policy "members can read their workspace"
  on workspaces for select using (is_workspace_member(id));

-- workspace_members
create policy "members can read membership"
  on workspace_members for select using (is_workspace_member(workspace_id));

create policy "admins can insert members"
  on workspace_members for insert with check (is_workspace_admin(workspace_id));

create policy "admins can delete members"
  on workspace_members for delete using (is_workspace_admin(workspace_id));

-- Allow the very first insert (workspace creator joins as admin before RLS would block)
create policy "user can insert own membership"
  on workspace_members for insert with check (user_id = auth.uid());

-- problem_clusters
create policy "members can read clusters"
  on problem_clusters for select using (is_workspace_member(workspace_id));

create policy "members can insert clusters"
  on problem_clusters for insert with check (is_workspace_member(workspace_id));

create policy "admins can update clusters"
  on problem_clusters for update using (is_workspace_admin(workspace_id));

create policy "admins can delete clusters"
  on problem_clusters for delete using (is_workspace_admin(workspace_id));

-- open_questions
create policy "members can read questions"
  on open_questions for select
  using (exists (
    select 1 from problem_clusters pc
    where pc.id = cluster_id and is_workspace_member(pc.workspace_id)
  ));

create policy "admins can manage questions"
  on open_questions for all
  using (exists (
    select 1 from problem_clusters pc
    where pc.id = cluster_id and is_workspace_admin(pc.workspace_id)
  ));

-- signals
create policy "members can read signals"
  on signals for select using (is_workspace_member(workspace_id));

create policy "members can insert signals"
  on signals for insert with check (is_workspace_member(workspace_id));

create policy "owner or admin can update signal"
  on signals for update using (
    logged_by = auth.uid() or is_workspace_admin(workspace_id)
  );

create policy "owner or admin can delete signal"
  on signals for delete using (
    logged_by = auth.uid() or is_workspace_admin(workspace_id)
  );

-- share_links
create policy "members can read share links"
  on share_links for select using (is_workspace_member(workspace_id));

create policy "admins can manage share links"
  on share_links for all using (is_workspace_admin(workspace_id));

-- invites
create policy "admins can manage invites"
  on invites for all using (is_workspace_admin(workspace_id));
